import{_ as a,o,c as t,a0 as r}from"./chunks/framework.BU6BaNeX.js";const p=JSON.parse('{"title":"Themes & Colormaps Reference","description":"Discover the hand-crafted, publication-ready themes and colormaps available in geoplot-themes, including Dark Matter and Retro Blueprint.","frontmatter":{"title":"Themes & Colormaps Reference","description":"Discover the hand-crafted, publication-ready themes and colormaps available in geoplot-themes, including Dark Matter and Retro Blueprint."},"headers":[],"relativePath":"api/themes-and-colors.md","filePath":"api/themes-and-colors.md"}'),s={name:"api/themes-and-colors.md"};function i(n,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="themes-colormaps" tabindex="-1">Themes &amp; Colormaps <a class="header-anchor" href="#themes-colormaps" aria-label="Permalink to &quot;Themes &amp; Colormaps&quot;">​</a></h1><p><code>geoplot-themes</code> ships with several hand-crafted, publication-ready themes.</p><h2 id="themes" tabindex="-1">Themes <a class="header-anchor" href="#themes" aria-label="Permalink to &quot;Themes&quot;">​</a></h2><p>You select a theme using the <code>theme</code> parameter in <code>plot_map_r()</code>.</p><ul><li><strong><code>natgeo_minimalist</code></strong>: A clean, elegant, serif-driven theme inspired by National Geographic magazines. Soft ivory background.</li><li><strong><code>dark_matter</code></strong>: A sleek, high-contrast dark theme ideal for dashboards and digital presentations.</li><li><strong><code>retro_blueprint</code></strong>: A thematic layout resembling old architectural and cartographic blueprints. Dark blue background with mono-spaced fonts.</li></ul><h2 id="colormaps" tabindex="-1">Colormaps <a class="header-anchor" href="#colormaps" aria-label="Permalink to &quot;Colormaps&quot;">​</a></h2><p>Colormaps define how your base data (raster or primary vector) is colored. Pass these to the <code>colormap</code> parameter.</p><ul><li><strong><code>elevation</code></strong>: Classic terrain colormap transitioning from dark green (low) to brown/white (high).</li><li><strong><code>neon</code></strong>: A vibrant, high-contrast mapping scale ideal for <code>dark_matter</code>.</li><li><strong><code>blueprint</code></strong>: Tonal blues designed to blend perfectly with the <code>retro_blueprint</code> theme.</li></ul>',8)])])}const g=a(s,[["render",i]]);export{p as __pageData,g as default};
